function abrirAbaModal(tab) {
  const abas = {
    senha:    { btn: 'tabBtnSenha',    painel: 'abaConfigSenha'    },
    sugestao: { btn: 'tabBtnSugestao', painel: 'abaConfigSugestao' },
    sobre:    { btn: 'tabBtnSobre',    painel: 'abaConfigSobre'    },
  };
  Object.entries(abas).forEach(([key, ids]) => {
    const btn = document.getElementById(ids.btn);
    const painel = document.getElementById(ids.painel);
    if (!btn || !painel) return;
    const ativo = key === tab;
    btn.classList.toggle('active', ativo);
    btn.style.color = ativo ? 'var(--blue)' : '#7f8c8d';
    btn.style.borderColor = ativo ? 'var(--blue)' : 'transparent';
    btn.style.fontWeight = ativo ? '700' : '600';
    painel.style.display = ativo ? 'flex' : 'none';
    if (ativo && key === 'sugestao') {
      carregarMinhasSugestoes();
    }
  });
}

function abrirModalSenha() {
  sbInjetarModalSenha();
  document.getElementById('inputNovaSenha').value = '';
  document.getElementById('inputConfirmarNovaSenha').value = '';
  const textSug = document.getElementById('inputSugestaoTexto');
  if (textSug) textSug.value = '';

  // Preenche nome/email do usuário logado na aba Senha
  (async () => {
    try {
      const session = await sbGetSession();
      const nome  = localStorage.getItem('igui_user_name') || session?.user?.email?.split('@')[0] || '—';
      const email = session?.user?.email || '—';
      const elNome  = document.getElementById('senhaModalNome');
      const elEmail = document.getElementById('senhaModalEmail');
      const elAv    = document.getElementById('senhaModalAvatar');
      const elAss   = document.getElementById('senhaModalAssinatura');
      if (elNome)  elNome.textContent  = nome;
      if (elEmail) elEmail.textContent = email;
      if (elAv) {
        const pts = nome.trim().split(/\s+/);
        elAv.textContent = ((pts[0]?.[0] || '') + (pts[1]?.[0] || '')).toUpperCase() || '?';
      }
      if (elAss) {
        try {
          const profile = await sbGetProfile();
          const isAdmin = profile?.role === 'admin';
          if (isAdmin) {
            elAss.innerHTML = `<span style="font-size:10px;font-weight:700;color:#7c3aed;background:#f3e8ff;border:1px solid #ddd6fe;border-radius:20px;padding:3px 9px;">Admin</span>`;
          } else if (!profile?.assinatura_expira_em) {
            elAss.innerHTML = `<span style="font-size:10px;font-weight:700;color:#7c3aed;background:#f3e8ff;border:1px solid #ddd6fe;border-radius:20px;padding:3px 9px;">♾️ Vitalício</span>`;
          } else {
            const exp = new Date(profile.assinatura_expira_em);
            const dias = Math.ceil((exp - new Date()) / (1000*60*60*24));
            const dataStr = exp.toLocaleDateString('pt-BR');
            if (dias < 0) {
              elAss.innerHTML = `<span style="font-size:10px;font-weight:700;color:#dc2626;background:#fef2f2;border:1px solid #fecaca;border-radius:20px;padding:3px 9px;">⛔ Expirada</span>`;
            } else if (dias <= 15) {
              elAss.innerHTML = `<span style="font-size:10px;font-weight:700;color:#d97706;background:#fffbeb;border:1px solid #fde68a;border-radius:20px;padding:3px 9px;">⚠️ Expira em ${dias}d</span><div style="font-size:10px;color:#8a9aaa;margin-top:2px;text-align:right;">${dataStr}</div>`;
            } else {
              elAss.innerHTML = `<span style="font-size:10px;font-weight:700;color:#16a34a;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:20px;padding:3px 9px;">✔ Ativa</span><div style="font-size:10px;color:#8a9aaa;margin-top:2px;text-align:right;">até ${dataStr}</div>`;
            }
          }
        } catch(_) {}
      }
    } catch (_) {}
  })();

  abrirAbaModal('senha');
  document.getElementById('modalSenhaGlobal').style.display = 'flex';
}

function fecharModalSenha() {
  const m = document.getElementById('modalSenhaGlobal');
  if (m) m.style.display = 'none';
}

async function confirmarAlterarSenha() {
  const p1 = document.getElementById('inputNovaSenha').value.trim();
  const p2 = document.getElementById('inputConfirmarNovaSenha').value.trim();
  
  if (!p1) {
    alert('Por favor, informe a nova senha.');
    return;
  }
  if (p1.length < 6) {
    alert('A senha deve ter no mínimo 6 caracteres.');
    return;
  }
  if (p1 !== p2) {
    alert('As senhas digitadas não coincidem.');
    return;
  }
  
  try {
    const { error } = await sb.auth.updateUser({ password: p1 });
    if (error) throw error;
    fecharModalSenha();
    if (typeof showToast === 'function') {
      showToast('✅ Senha alterada com sucesso!', 'ok');
    } else {
      alert('Senha alterada com sucesso!');
    }
  } catch(e) {
    alert('Erro ao alterar senha: ' + e.message);
  }
}

async function confirmarEnviarSugestao() {
  const texto = document.getElementById('inputSugestaoTexto').value.trim();
  if (!texto) {
    alert('Por favor, digite sua sugestão antes de enviar.');
    return;
  }

  try {
    const user = await sbGetUser();
    const profile = await sbGetProfile();
    const userName = profile?.name || user?.email?.split('@')[0] || 'Usuário';

    // Grava na tabela customizada 'suggestions'
    const { error } = await sb.from('suggestions').insert({
      user_id: user.id,
      user_name: userName,
      user_email: user.email,
      content: texto
    });

    if (error) throw error;

    document.getElementById('inputSugestaoTexto').value = '';
    fecharModalSenha();
    if (typeof showToast === 'function') {
      showToast('✅ Sugestão enviada com sucesso! Obrigado pelo feedback.', 'ok');
    } else {
      alert('Sugestão enviada com sucesso! Obrigado pelo feedback.');
    }
  } catch (e) {
    alert('Erro ao enviar sugestão: ' + e.message);
  }
}

async function sbListarMinhasSugestoes() {
  const user = await sbGetUser();
  if (!user) return [];
  const { data, error } = await sb.from('suggestions')
    .select('*')
    .eq('user_id', user.id)
    .order('created_at', { ascending: false });
  if (error) throw error;
  return data || [];
}

async function carregarMinhasSugestoes() {
  const container = document.getElementById('listaMinhasSugestoes');
  if (!container) return;
  container.innerHTML = '<div style="color:#8a9aaa; text-align:center; padding:10px;">Carregando...</div>';
  try {
    const list = await sbListarMinhasSugestoes();
    if (!list.length) {
      container.innerHTML = '<div style="color:#8a9aaa; text-align:center; padding:10px; font-style:italic;">Nenhuma sugestão enviada ainda.</div>';
      return;
    }
    container.innerHTML = '';
    list.forEach(sug => {
      const dateStr = new Date(sug.created_at).toLocaleDateString('pt-BR');
      const item = document.createElement('div');
      item.style.cssText = 'padding:8px 10px; border-radius:6px; background:#f8fafc; border:1px solid #edf2f6; display:flex; flex-direction:column; gap:4px;';
      
      const header = document.createElement('div');
      header.style.cssText = 'display:flex; justify-content:space-between; align-items:center; font-size:10px; color:#8a9aaa; font-weight:600;';
      header.innerHTML = `<span>📅 ${dateStr}</span>`;
      
      const badge = document.createElement('span');
      if (sug.done) {
        badge.style.cssText = 'display:inline-flex; align-items:center; gap:2px; font-size:10px; font-weight:700; color:#2e7d32;';
        badge.textContent = '✓ Resolvido';
      } else {
        badge.style.cssText = 'display:inline-flex; align-items:center; gap:2px; font-size:10px; font-weight:700; color:#b78103;';
        badge.textContent = '⏰ Pendente';
      }
      header.appendChild(badge);
      
      const content = document.createElement('div');
      content.style.cssText = 'color:#2c3e50; line-height:1.4; word-break:break-word;';
      content.textContent = sug.content;
      
      item.appendChild(header);
      item.appendChild(content);
      container.appendChild(item);
    });
  } catch(e) {
    container.innerHTML = `<div style="color:#e74c3c; text-align:center; padding:10px;">Erro ao carregar: ${e.message}</div>`;
  }
}

