/**
 * Salva (insere ou atualiza) um projeto no Supabase.
 * payload: { form, imgs, acc, itens, selectedImgs, secAtiva, obsPadrao, step }
 * existingId: UUID se estiver atualizando
 * Retorna o UUID do projeto salvo.
 */
async function sbSalvarProjeto(payload, existingId = null) {
  const user = await sbGetUser();
  if (!user) throw new Error('Usuário não autenticado');

  const projectId = existingId || crypto.randomUUID();

  // Serializa: sobe imagens novas e converte para URLs
  const sessionData = await sbSerializeSessionData(payload, user.id, projectId);
  sessionData.form       = payload.form;
  sessionData.obsPadrao  = payload.obsPadrao;
  sessionData.step       = payload.step;

  // Campos comuns (sem user_id — nunca alterar o dono original ao atualizar)
  const fields = {
    client_name:   payload.form?.cliente    || '',
    project_code:  payload.form?.id_projeto || '',
    city:          payload.form?.cidade     || '',
    store:         payload.form?.loja       || '',
    model:         payload.form?.modelo     || '',
    proj_date:     payload.form?.data_proj  || '',
    session_data:  sessionData,
    thumbnail_url: sessionData.imgs?.['3d']?.[0] || null,
    created_by:    payload.form?.usuario_logado || '',
  };

  let error;
  if (existingId) {
    // UPDATE: preserva user_id original (não troca dono)
    ({ error } = await sb.from('projects').update(fields).eq('id', projectId));
  } else {
    // INSERT: define user_id como o usuário atual
    ({ error } = await sb.from('projects').insert({ id: projectId, user_id: user.id, ...fields }));
  }
  if (error) throw error;
  return projectId;
}

