/** Exclui um projeto e seus arquivos no Storage. */
async function sbDeletarProjeto(id) {
  const user = await sbGetUser();

  // Remover arquivos do Storage (lista e exclui)
  try {
    const prefix = `${user.id}/${id}/`;
    const { data: files } = await sb.storage.from(BUCKET).list(`${user.id}/${id}`);
    if (files?.length) {
      const paths = files.map(f => `${user.id}/${id}/${f.name}`);
      await sb.storage.from(BUCKET).remove(paths);
    }
  } catch (e) { console.warn('Storage cleanup error:', e); }

  const { error } = await sb.from('projects').delete().eq('id', id);
  if (error) throw error;
}

